#!/usr/bin/env python3
import sys, time, json
# Simple in-memory rate limiting per user (user ID passed as first arg)
RATE_LIMIT = 100  # queries per minute per user
_user_counts = {}
_last_reset = time.time()

def reset_counts():
    global _user_counts, _last_reset
    now = time.time()
    if now - _last_reset >= 60:
        _user_counts = {}
        _last_reset = now

def rate_limit(user, count=1):
    reset_counts()
    _user_counts[user] = _user_counts.get(user, 0) + count
    return "THROTTLED" if _user_counts[user] > RATE_LIMIT else "allowed"

def perturb_output(confidence):
    # round to one decimal place
    return round(confidence, 1)

if __name__ == '__main__':
    # Expect JSON lines from stdin: {"user":"id","confidence":float}
    for line in sys.stdin:
        try:
            data = json.loads(line.strip())
            user = data.get('user')
            conf = data.get('confidence', 0.0)
            rl = rate_limit(user)
            pert = perturb_output(conf)
            out = {"rate": rl, "perturbed_confidence": pert}
            print(json.dumps(out))
        except Exception as e:
            print(json.dumps({"error": str(e)}))
